def num_distinct(s: str, t: str) -> int:
    """Count distinct subsequences of s that equal t."""
    n, m = len(s), len(t)
    if m == 0:
        return 1
    if n == 0:
        return 0

    # dp[j] = number of ways to form t[0:j] using characters of s processed so far
    dp = [0] * (m + 1)
    dp[0] = 1  # Empty t can be formed in 1 way

    for i in range(n):
        # Iterate backwards to avoid using updated values from current iteration
        for j in range(m, 0, -1):
            if s[i] == t[j - 1]:
                dp[j] += dp[j - 1]

    return dp[m]
